import { useState } from 'react';
import '../styles/CreateGroup.css';

export default function CreateGroup() {
    const [name, setName] = useState('');
    const [image, setImage] = useState(null);
    const [description, setDescription] = useState('');

    const handleSubmit = (e) => {
        e.preventDefault();

        // Tu peux envoyer ces données à ton API ou les stocker localement
        const formData = new FormData();
        formData.append('name', name);
        formData.append('image', image);
        formData.append('description', description);

        console.log("Formulaire soumis :", { name, image, description });
        alert("Groupe créé !");
    };

    return (
        <div className="create-group-container">
            <h1 className="form-title">Créer un nouveau groupe</h1>

            <form className="create-group-form" onSubmit={handleSubmit}>
                <div className="form-group">
                    <label>Nom de la destination</label>
                    <input
                        type="text"
                        value={name}
                        onChange={(e) => setName(e.target.value)}
                        required
                    />
                </div>

                <div className="form-group">
                    <label>Image du groupe</label>
                    <input
                        type="file"
                        accept="image/*"
                        onChange={(e) => setImage(e.target.files[0])}
                        required
                    />
                </div>

                <div className="form-group">
                    <label>Descriptif</label>
                    <textarea
                        value={description}
                        onChange={(e) => setDescription(e.target.value)}
                        rows="4"
                        required
                    />
                </div>

                <button type="submit" className="submit-button">
                    Créer le groupe
                </button>
            </form>
        </div>
    );
}
